import React, { Suspense, lazy, useState, useEffect, useCallback } from 'react';
import { Sidebar } from './Sidebar';
import { Footer as SaveStatusFooter } from './Footer';
import { ErrorToastContainer } from './ErrorToast';
import { SupportModal } from './SupportModal';
import { AboutModal } from './AboutModal';
import { PrivacyModal } from './PrivacyModal';
import { OnboardingModal } from './OnboardingModal';
import { CommandPalette } from './CommandPalette';
import { useSidebarStore } from '../stores/useSidebarStore';
import { useTerminalStore } from '../stores/useTerminalStore';
import { useProjectContextStore } from '../stores/useProjectContextStore';

// Lazy load AITerminal to avoid loading 900KB+ of AI provider SDKs in the main bundle
const AITerminal = lazy(() => import('./AITerminal').then(m => ({ default: m.AITerminal })));

/**
 * Layout Component with Sidebar Navigation
 */
interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const { isCollapsed, toggleMobileMenu } = useSidebarStore();
  const { isOpen: isTerminalOpen, toggleTerminal } = useTerminalStore();
  const toggleProjectDropdown = useProjectContextStore((s) => s.toggleDropdown);
  const [showSupportModal, setShowSupportModal] = useState(false);
  const [supportModalTab, setSupportModalTab] = useState<'report' | 'help' | 'docs'>('report');
  const [showCommandPalette, setShowCommandPalette] = useState(false);
  const [showAboutModal, setShowAboutModal] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);
  const [showOnboardingModal, setShowOnboardingModal] = useState(false);

  // Handler for opening support modal from command palette
  const handleOpenSupportModal = (tab: 'report' | 'help' | 'docs') => {
    setSupportModalTab(tab);
    setShowSupportModal(true);
    setShowCommandPalette(false);
  };

  // Handler for opening various modals from command palette
  const handleOpenModal = useCallback((modalId: string) => {
    setShowCommandPalette(false);
    switch (modalId) {
      case 'about':
        setShowAboutModal(true);
        break;
      case 'privacy':
        setShowPrivacyModal(true);
        break;
      case 'onboarding':
        setShowOnboardingModal(true);
        break;
      case 'support':
        setShowSupportModal(true);
        break;
      default:
        break;
    }
  }, []);

  // Global keyboard shortcuts
  // Using capture phase to intercept before browser handles F1 and Cmd+K
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd+K (Mac) or Ctrl+K (Windows/Linux) - open command palette
      if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        e.stopPropagation();
        setShowCommandPalette(true);
        return;
      }

      // F1 key - open help modal
      if (e.key === 'F1') {
        e.preventDefault();
        e.stopPropagation();
        setShowSupportModal(true);
        return;
      }

      // Ctrl+/ (Windows/Linux) or Cmd+/ (Mac) - open help modal
      if (e.key === '/' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        e.stopPropagation();
        setShowSupportModal(true);
        return;
      }

      // Cmd+Shift+P (Mac) or Ctrl+Shift+P (Windows/Linux) - toggle project switcher
      if (e.key === 'p' && (e.metaKey || e.ctrlKey) && e.shiftKey) {
        e.preventDefault();
        e.stopPropagation();
        toggleProjectDropdown();
        return;
      }
    };

    // Use capture: true to intercept events before they reach the browser
    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, [toggleProjectDropdown]);

  return (
    <div className="app h-screen bg-surface-light dark:bg-surface-dark flex overflow-hidden">
      {/* Skip to main content link - visible on focus for keyboard users */}
      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-1/2 focus:-translate-x-1/2 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent-blue focus:text-white focus:rounded-button focus:shadow-lg"
      >
        Skip to main content
      </a>

      {/* Mobile hamburger button */}
      <button
        onClick={toggleMobileMenu}
        className="lg:hidden fixed top-4 left-4 z-50 p-2 rounded-button bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark shadow-lg transition-all duration-standard ease-smooth"
        aria-label="Toggle navigation menu"
      >
        <span className="text-xl" aria-hidden="true">☰</span>
      </button>

      <Sidebar />

      {/* Main content area with margin for sidebar */}
      <div className="flex-1 flex flex-col transition-all duration-200 overflow-x-hidden overflow-y-hidden">
        <main
          id="main-content"
          role="main"
          tabIndex={-1}
          className={`
            flex-1 py-6 overflow-y-auto
            transition-[margin] duration-200
            focus:outline-none
            ${/* Mobile: no margin (sidebars are overlays) */ ''}
            ml-0 mr-0
            ${/* Desktop: left margin for navigation sidebar */ ''}
            ${isCollapsed ? 'lg:ml-[60px]' : 'lg:ml-[210px]'}
            ${/* Desktop: right margin for AI terminal */ ''}
            ${isTerminalOpen ? 'lg:mr-[375px]' : 'lg:mr-0'}
          `}
        >
          <div className="w-full px-6">
            {children}
          </div>
        </main>
      </div>

      {/* Save Status Footer (floating pill at bottom-center) */}

/**
 * Synapse Types
 *
 * Type definitions for Synapse - Neuman Brain's neural search interface.
 * Provides quick access to all platform data via Ctrl+K / Cmd+K.
 */

import type { ReactNode } from 'react';

/**
 * Result types that can appear in search results
 */
export type SearchResultType =
  | 'note'
  | 'task'
  | 'event'
  | 'bookmark'
  | 'page'
  | 'action'
  | 'external'
  | 'diagram'
  | 'form'
  | 'time-entry'
  | 'faq'
  | 'help'
  | 'widget'
  | 'setting'
  | 'automation'
  | 'template'
  | 'project'
  | 'shortcut';

/**
 * Search result item displayed in the command palette
 */
export interface SearchResult {
  /** Unique identifier for this result */
  id: string;
  /** Type of result for categorization and icon selection */
  type: SearchResultType;
  /** Primary display text */
  title: string;
  /** Secondary text (path, description, URL, etc.) */
  subtitle?: string;
  /** Icon to display (emoji, Lucide component, or custom ReactNode) */
  icon?: string | ReactNode;
  /** Relevance score for sorting (higher = more relevant) */
  score: number;
  /** Action to execute when selected */
  action: () => void;
  /** Optional preview content */
  preview?: string;
  /** Additional metadata for filtering/display */
  metadata?: Record<string, unknown>;
  /** Keywords for fuzzy matching (in addition to title/subtitle) */
  keywords?: string[];
}

/**
 * Search source configuration for dynamic data registration
 */
export interface SearchSource {
  /** Unique identifier for this source */
  id: string;
  /** Display name for the source */
  name: string;
  /** Result type produced by this source */
  type: SearchResultType;
  /** Icon for results from this source */
  icon: string | ReactNode;
  /** Function that returns all searchable items */
  getItems: () => SearchResult[];
  /** Priority for ordering sources (higher = shown first) */
  priority?: number;
  /** Whether this source is enabled */
  enabled?: boolean;
}

/**
 * External search engine configuration
 */
export interface SearchEngine {
  /** Unique identifier */
  id: string;
  /** Display name */
  name: string;
  /** URL template with {query} placeholder */
  urlTemplate: string;
  /** Favicon URL for the search engine (light mode or universal) */
  faviconUrl: string;
  /** Optional dark mode favicon URL (for icons that don't show well on dark backgrounds) */
  faviconUrlDark?: string;
  /** Keyboard shortcut hint (optional) */
  shortcut?: string;
}

/**
 * Built-in search engines with real favicons
 */
export const SEARCH_ENGINES: SearchEngine[] = [
  {
    id: 'google',
    name: 'Google',
    urlTemplate: 'https://www.google.com/search?q={query}',
    faviconUrl: 'https://www.google.com/favicon.ico',
  },
  {
    id: 'duckduckgo',
    name: 'DuckDuckGo',
    urlTemplate: 'https://duckduckgo.com/?q={query}',
    faviconUrl: 'https://duckduckgo.com/favicon.ico',
  },
  {
    id: 'bing',
    name: 'Bing',
    urlTemplate: 'https://www.bing.com/search?q={query}',
    faviconUrl: 'https://www.bing.com/favicon.ico',
  },
  {
    id: 'brave',
    name: 'Brave Search',
    urlTemplate: 'https://search.brave.com/search?q={query}',
    faviconUrl: 'https://brave.com/static-assets/images/brave-favicon.png',
  },
  {
    id: 'ecosia',
    name: 'Ecosia',
    urlTemplate: 'https://www.ecosia.org/search?q={query}',
    faviconUrl: 'https://www.ecosia.org/favicon.ico',
  },
  {
    id: 'startpage',
    name: 'Startpage',
    urlTemplate: 'https://www.startpage.com/sp/search?query={query}',
    faviconUrl: 'https://www.startpage.com/favicon.ico',
  },
  {
    id: 'wikipedia',
    name: 'Wikipedia',
    urlTemplate: 'https://en.wikipedia.org/w/index.php?search={query}',
    faviconUrl: 'https://en.wikipedia.org/favicon.ico',
  },
  {
    id: 'github',
    name: 'GitHub',
    urlTemplate: 'https://github.com/search?q={query}',
    faviconUrl: 'https://github.com/favicon.ico',
    faviconUrlDark: 'https://github.githubassets.com/favicons/favicon-dark.svg',
  },
  {
    id: 'stackoverflow',
    name: 'Stack Overflow',
    urlTemplate: 'https://stackoverflow.com/search?q={query}',
    faviconUrl: 'https://cdn.sstatic.net/Sites/stackoverflow/Img/favicon.ico',
  },
  {
    id: 'youtube',
    name: 'YouTube',
    urlTemplate: 'https://www.youtube.com/results?search_query={query}',
    faviconUrl: 'https://www.youtube.com/favicon.ico',
  },
  {
    id: 'chatgpt',
    name: 'ChatGPT',
    urlTemplate: 'https://chatgpt.com/?hints=search&q={query}',
    faviconUrl: 'https://cdn.oaistatic.com/assets/favicon-miwirzcw.ico',
  },
  {
    id: 'perplexity',
    name: 'Perplexity',
    urlTemplate: 'https://www.perplexity.ai/search?q={query}',
    faviconUrl: 'https://uxwing.com/wp-content/themes/uxwing/download/brands-and-social-media/perplexity-ai-icon.png',
  },
];

/**
 * Navigation pages available in the app
 */
export interface NavigationPage {
  id: string;
  name: string;
  path: string;
  icon: string;
  keywords: string[];
  description?: string;
}

/**
 * All navigable pages in the application
 */
export const NAVIGATION_PAGES: NavigationPage[] = [
  {
    id: 'dashboard',
    name: 'Dashboard',
    path: '/',
    icon: '🏠',
    keywords: ['home', 'overview', 'widgets', 'main'],
    description: 'Main dashboard with widgets',
  },
  {
    id: 'notes',
    name: 'Notes',
    path: '/notes',
    icon: '📝',
    keywords: ['note', 'write', 'document', 'text', 'markdown'],
    description: 'Create and manage notes',
  },
  {
    id: 'graph',
    name: 'Graph View',
    path: '/graph',
    icon: '🕸️',
    keywords: ['graph', 'network', 'links', 'connections', 'knowledge'],
    description: 'Visualize note connections',
  },
  {
    id: 'tasks',
    name: 'Tasks',
    path: '/tasks',
    icon: '✅',
    keywords: ['task', 'todo', 'kanban', 'project', 'board'],
    description: 'Kanban task management',
  },
  {
    id: 'schedule',
    name: 'Schedule',
    path: '/schedule',
    icon: '📅',
    keywords: ['calendar', 'schedule', 'time', 'events', 'tracking'],
    description: 'Calendar and time tracking',
  },
  {
    id: 'links',
    name: 'Link Library',
    path: '/links',
    icon: '🔗',
    keywords: ['bookmark', 'link', 'url', 'web', 'save'],
    description: 'Saved bookmarks and links',
  },
  {
    id: 'diagrams',
    name: 'Diagrams',
    path: '/diagrams',
    icon: '📊',
    keywords: ['diagram', 'flowchart', 'chart', 'draw', 'visual'],
    description: 'Create diagrams and flowcharts',
  },
  {
    id: 'forms',
    name: 'Forms',
    path: '/forms',
    icon: '📋',
    keywords: ['form', 'survey', 'questionnaire', 'input'],
    description: 'Build and manage forms',
  },
  {
    id: 'automations',
    name: 'Automations',
    path: '/automations',
    icon: '⚡',
    keywords: ['automation', 'workflow', 'rule', 'trigger', 'action'],
    description: 'Task automation rules',
  },
  {
    id: 'settings',
    name: 'Settings',
    path: '/settings',
    icon: '⚙️',
    keywords: ['settings', 'preferences', 'config', 'options', 'theme'],
    description: 'App settings and preferences',
  },
];

/**
 * Command palette state
 */
export interface CommandPaletteState {
  isOpen: boolean;
  query: string;
  selectedIndex: number;
  results: SearchResult[];
  isLoading: boolean;
}

import React from 'react';
import { Modal } from './Modal';

interface KeyboardShortcutsHelpProps {
  isOpen: boolean;
  onClose: () => void;
}

/**
 * Keyboard Shortcuts Help Modal
 * Shows all available keyboard shortcuts for the Kanban board
 */
export const KeyboardShortcutsHelp: React.FC<KeyboardShortcutsHelpProps> = ({
  isOpen,
  onClose,
}) => {
  const shortcuts = [
    {
      category: 'Navigation',
      items: [
        { keys: ['J'], description: 'Move down to next task' },
        { keys: ['K'], description: 'Move up to previous task' },
        { keys: ['H'], description: 'Move left to previous column' },
        { keys: ['L'], description: 'Move right to next column' },
      ],
    },
    {
      category: 'Actions',
      items: [
        { keys: ['N'], description: 'Create new task in current column' },
        { keys: ['E'], description: 'Edit selected task' },
        { keys: ['D'], description: 'Delete selected task' },
      ],
    },
    {
      category: 'General',
      items: [
        { keys: ['?'], description: 'Toggle this help menu' },
        { keys: ['Esc'], description: 'Clear selection / Close dialogs' },
      ],
    },
  ];

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="⌨️ Keyboard Shortcuts">
      <div className="space-y-6">
        {shortcuts.map((section) => (
          <div key={section.category}>
            <h4 className="text-sm font-semibold text-accent-primary mb-3 uppercase tracking-wide">
              {section.category}
            </h4>
            <div className="space-y-2">
              {section.items.map((shortcut, index) => (
                <div
                  key={index}
                  className="flex items-center justify-between py-2 border-b border-neutral-lightGray dark:border-neutral-darkGray last:border-0"
                >
                  <span className="text-sm text-gray-700 dark:text-gray-300">
                    {shortcut.description}
                  </span>
                  <div className="flex gap-1">
                    {shortcut.keys.map((key, keyIndex) => (
